create or replace function public.update_my_profile(p_full_name text) returns void language plpgsql security definer set search_path=public as $$ begin update public.profiles set full_name=trim(p_full_name) where id=auth.uid(); end $$;
create or replace function public.admin_update_collaborator(p_id uuid,p_full_name text,p_role public.app_role) returns void language plpgsql security definer set search_path=public as $$ begin if not public.has_role(array['admin']::public.app_role[]) then raise exception 'Solo administradores'; end if; if not exists(select 1 from public.profiles where id=p_id and tenant_id=public.current_tenant_id()) then raise exception 'Colaborador no pertenece a tu tienda'; end if; update public.profiles set full_name=trim(p_full_name),role=p_role where id=p_id; end $$;
grant execute on function public.update_my_profile(text),public.admin_update_collaborator(uuid,text,public.app_role) to authenticated;
